:host.chat-window-host {
  display: block;
  height: 100%;
  min-height: 0;
}

.chat-window-container {
  position: relative;
  background: var(--surface, var(--background));
  border-radius: var(--border-radius-lg, 12px);
  box-shadow: var(--shadow-lg, 0 4px 24px rgba(0, 0, 0, 0.12));
  display: flex;
  flex-direction: column;
  transition: all var(--animation-duration-normal, 0.3s) ease;
  max-height: 1000px;
  overflow: hidden;
  border: 1px solid var(--border);
}

.chat-window-container.embedded {
  height: 100%;
  max-height: none;
  border-radius: 0;
  box-shadow: none;
  border: none;
  min-height: 0;
}

.chat-window-container.fullscreen {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  z-index: 1000;
  border-radius: 0;
}

.chat-window-container.popout {
  position: fixed;
  max-height: 1000px;
  bottom: 24px;
  right: 80px;
  min-width: 280px;
  max-width: min(800px, calc(100vw - 96px));
  z-index: 1001;
  box-shadow: var(--shadow-xl, 0 4px 24px rgba(0, 0, 0, 0.25));
}

.chat-window-container.hidden {
  display: none;
}

.chat-window-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 18px;
  background: linear-gradient(
    135deg,
    color-mix(
        in srgb,
        var(--local-accent, var(--primary, var(--accent))) 8%,
        transparent
      )
      0%,
    color-mix(
      in srgb,
      var(--local-complement, var(--surface, var(--background))) 32%,
      var(--surface, var(--background))
      )
      100%
  );
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--local-border-color, var(--border));
  position: relative;

  &::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(
      90deg,
      transparent,
      var(--local-accent),
      transparent
    );
    opacity: 0.3;
  }
}

.header-content {
  display: flex;
  align-items: center;
  gap: 12px;
}

.contact-avatar {
  position: relative;
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 4px;
}

.avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  object-fit: cover;
}

.single-avatar {
  width: 40px;
  height: 40px;
}

.multiple-avatars {
  position: absolute;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  object-fit: cover;

  &:first-child {
    z-index: 3;
  }

  &:nth-child(2) {
    z-index: 2;
    transform: translateX(-8px);
  }

  &:nth-child(3) {
    z-index: 1;
    transform: translateX(-16px);
  }
}

.contact-details {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 2px;
}

.contact-name {
  font-family: var(--font-heading, inherit);
  font-weight: 600;
  color: var(--foreground);
  font-size: 1rem;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  letter-spacing: 0.02em;
}

.contact-status {
  font-family: var(--font-body, inherit);
  font-size: 0.8rem;
  color: var(--foreground);
  opacity: 0.7;
  display: flex;
  align-items: center;
  gap: 6px;

  &.status-online {
    color: var(--success);
    .status-dot {
      background: var(--success);
      box-shadow: 0 0 6px color-mix(in srgb, var(--success) 55%, transparent);
      animation: status-pulse 2s ease-in-out infinite;
    }
  }

  &.status-away {
    color: var(--warning);
    .status-dot {
      background: var(--warning);
      box-shadow: 0 0 6px color-mix(in srgb, var(--warning) 55%, transparent);
    }
  }

  &.status-busy {
    color: var(--danger);
    .status-dot {
      background: var(--danger);
      box-shadow: 0 0 6px color-mix(in srgb, var(--danger) 55%, transparent);
    }
  }

  &.status-offline {
    color: var(--muted-foreground, var(--foreground));
    .status-dot {
      background: var(--muted-foreground, var(--foreground));
      box-shadow: none;
      animation: none;
    }
  }
}

.status-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--success);
  box-shadow: 0 0 6px color-mix(in srgb, var(--success) 55%, transparent);
  animation: status-pulse 2s ease-in-out infinite;
}

@keyframes status-pulse {
  0%,
  100% {
    opacity: 1;
    box-shadow: 0 0 4px color-mix(in srgb, var(--success) 45%, transparent);
  }
  50% {
    opacity: 0.7;
    box-shadow: 0 0 8px color-mix(in srgb, var(--success) 65%, transparent);
  }
}

.chat-window-actions {
  display: flex;
  gap: 6px;
}

.chat-window-action-button {
  display: block;
  width: 40px;
  min-width: 40px;
}

.chat-window-close-button {
  width: 44px;
}

.chat-window-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
  background: var(--background);
}

.header-divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--accent), transparent);
  opacity: 0.4;
  margin: 0;
  padding: 0;
}

.participants-section {
  padding: 10px 18px;
  background: color-mix(in srgb, var(--foreground) 2%, transparent);
  border-bottom: 1px solid var(--border);
}

.participants-divider {
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent,
    var(--complement),
    transparent
  );
  opacity: 0.3;
  margin: 0;
  padding: 0;
}

.no-participants {
  padding: 16px;
  text-align: center;
  color: var(--muted-foreground, var(--foreground));
  opacity: 0.7;
  font-style: italic;
}

.ai-status-indicator {
  padding: 8px 16px;
  background: var(--local-background, var(--background));
  border-top: 1px solid var(--local-border-color, var(--border));
  font-style: italic;
  color: var(--local-accent, var(--primary, var(--accent)));
  font-size: 0.9em;
  display: flex;
  align-items: center;
  justify-content: center;
}

.thinking-dots,
.typing-indicator {
  display: inline-block;
  width: 20px;
  height: 4px;
  background: var(--local-accent, var(--primary, var(--accent)));
  border-radius: 2px;
  animation: pulse 1.5s ease-in-out infinite;
  margin-right: 8px;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 0.4;
  }
  50% {
    opacity: 1;
  }
}

