      <lib-participants [participants]="contact"></lib-participants>
    </div> -->
    <!-- <div class="participants-divider"></div> -->
    <lib-message-list
      [conversation]="messages"
      [messages]="messages.messages"
      [contacts]="contact"
      [currentUserId]="currentUserId"
      [typingUsers]="typingUsers"
      (reactionAdded)="onReactionAdded($event)"
      (reactionRemoved)="onReactionRemoved($event)"
