    } @else {
    <div class="no-participants">No participants</div>
    <lib-message-list
      [conversation]="messages"
      [messages]="messages.messages"
      [contacts]="[]"
      [currentUserId]="currentUserId"
      [typingUsers]="typingUsers"
      (reactionAdded)="onReactionAdded($event)"
      (reactionRemoved)="onReactionRemoved($event)"
    ></lib-message-list>
    } @if(aiIsResponding || aiThinkingMessage) {
    <div class="ai-status-indicator">
      @if(aiThinkingMessage) {
