        <span class="thinking-dots"></span>
        {{ aiThinkingMessage }}
      </div>
      } @else {
      <div class="ai-responding">
        <span class="typing-indicator"></span>
        AI is responding...
      </div>
      }
    </div>
    }

    <lib-compose-chat
      (messageSubmitted)="onMessageSubmitted($event)"
    ></lib-compose-chat>
  </div>
</div>
}

