import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule, NgClass, NgIf, DatePipe } from '@angular/common';

import { ChatContact } from '../../chat-ui.component';
import {
  ChatConversation,
  ChatMessage,
  MessageReaction,
} from '../../../types/message';
import { ProfilePhotoComponent } from '@optimistic-tanuki/profile-ui';

@Component({
  selector: 'lib-message-list',
  imports: [CommonModule, NgClass, NgIf, DatePipe, ProfilePhotoComponent],
  templateUrl: './message-list.component.html',
  styleUrls: ['./message-list.component.scss'],
})
/**
 * Displays a list of messages in a chat conversation.
 */
export class MessageListComponent {
  /**
   * The list of contacts in the chat.
   */
  @Input() contacts: ChatContact[] = [];
  @Input() conversation?: ChatConversation;
  /**
   * The list of messages in the conversation.
   */
  @Input() messages: ChatMessage[] = [];
  /**
   * Current user ID for determining sent/received messages.
   */
  @Input() currentUserId: string = '';
  /**
   * IDs of users currently typing in this conversation.
   */
  @Input() typingUsers: string[] = [];
  /**
   * Emitted when a reaction is added to a message.
   */
  @Output() reactionAdded = new EventEmitter<{
    messageId: string;
    emoji: string;
  }>();
  /**
   * Emitted when a reaction is removed from a message.
   */
  @Output() reactionRemoved = new EventEmitter<{
    messageId: string;
    emoji: string;
  }>();

  /**
   * Common emoji reactions that can be added.
   */
  commonEmojis = ['👍', '❤️', '😂', '😮', '😢', '🎉', '🔥', '👏'];

  /**
   * Whether the emoji picker is currently shown.
   */
  showEmojiPicker: { [messageId: string]: boolean } = {};

  getMessageContent(content: string): string {
    // Strip HTML if needed
    return content.replace(/<[^>]*>?/gm, '');
  }

  getContact(senderId: string): ChatContact | undefined {
    const participantProfile = this.conversation?.participantProfiles?.find(
      (profile) => profile.id === senderId
    );

    if (participantProfile) {
      return {
        id: participantProfile.id,
        name: participantProfile.name,
        profilePic: participantProfile.profilePic,
        avatarUrl: participantProfile.avatarUrl,
      };
    }

    return this.contacts.find((c) => c.id === senderId);
  }

  isReceived(senderId: string): boolean {
    return senderId !== this.currentUserId;
  }

  isSent(senderId: string): boolean {
    return senderId === this.currentUserId;
  }

  isReadBy(message: ChatMessage, contactId: string): boolean {
    return message.readBy?.includes(contactId) || false;
  }

  getMessageStatusClass(message: ChatMessage): string {
    if (message.type === 'system') {
      return 'status-system';
    }
    if (message.isDeleted) {
      return 'status-deleted';
    }
    if (
      this.isSent(message.senderId) &&
      message.readBy &&
      message.readBy.length > 0
    ) {
      return 'status-read';
    }
    if (this.isSent(message.senderId)) {
      return 'status-sent';
    }
    return 'status-delivered';
  }

  hasReactions(message: ChatMessage): boolean {
    return !!(message.reactions && message.reactions.length > 0);
  }

  getReactionsByEmoji(
    message: ChatMessage
  ): { emoji: string; count: number; users: string[]; isActive: boolean }[] {
    if (!message.reactions) return [];

    const reactionMap = new Map<string, string[]>();
    message.reactions.forEach((r) => {
      const users = reactionMap.get(r.emoji) || [];
      users.push(r.userId);
      reactionMap.set(r.emoji, users);
    });

    return Array.from(reactionMap.entries()).map(([emoji, users]) => ({
      emoji,
      count: users.length,
      users,
      isActive: users.includes(this.currentUserId),
    }));
  }

  toggleEmojiPicker(messageId: string) {
    this.showEmojiPicker[messageId] = !this.showEmojiPicker[messageId];
  }

  addReaction(messageId: string, emoji: string) {
    this.reactionAdded.emit({ messageId, emoji });
    this.showEmojiPicker[messageId] = false;
  }

  removeReaction(messageId: string, emoji: string) {
    this.reactionRemoved.emit({ messageId, emoji });
  }

  getContactName(userId: string): string {
    const contact = this.contacts.find((c) => c.id === userId);
    return contact?.name || 'Unknown';
  }

  isTyping(userId: string): boolean {
    return this.typingUsers.includes(userId);
  }

  isFirstInGroup(messages: ChatMessage[], index: number): boolean {
    if (index === 0) return true;

    const currentSender = messages[index].senderId;
    const previousSender = messages[index - 1].senderId;

    return currentSender !== previousSender;
  }

  isLastInGroup(messages: ChatMessage[], index: number): boolean {
    if (index === messages.length - 1) return true;

    const currentSender = messages[index].senderId;
    const nextSender = messages[index + 1].senderId;

    return currentSender !== nextSender;
  }
}

styleUrlsData.data:
:host {
  display: flex;
  flex: 1 1 auto;
  min-height: 0;
}

.message-list {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-md, 16px);
  background: var(--background);
  color: var(--foreground);
  scroll-behavior: smooth;
  min-height: 0;

  &::-webkit-scrollbar {
    width: 6px;
  }

  &::-webkit-scrollbar-track {
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    background: var(--border);
    border-radius: 3px;

    &:hover {
      background: var(--accent);
    }
  }
}

.message {
  margin: 6px 0;
  display: flex;
  align-items: flex-start;
  gap: 10px;
  animation: message-appear 0.25s ease-out;

  @keyframes message-appear {
    from {
      opacity: 0;
      transform: translateY(8px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }

  &.message-received {
    flex-direction: row;

    .message-avatar {
      margin-right: 0;
      flex-shrink: 0;
    }

    .message-bubble {
      align-items: flex-start;
      max-width: 75%;

      .message-content {
        background: color-mix(
          in srgb,
          var(--local-complement) 15%,
          transparent
        );
        backdrop-filter: blur(8px);
        -webkit-backdrop-filter: blur(8px);
        border: 1px solid var(--local-border-color);
        border-radius: var(--border-radius-xl, 18px);
        border-top-left-radius: var(--border-radius-sm, 4px);
        box-shadow: var(--shadow-sm);
      }
    }
  }

  &.message-sent {
    flex-direction: row-reverse;

    .message-avatar {
      margin-left: 0;
      flex-shrink: 0;
    }

    .message-bubble {
      align-items: flex-end;
      max-width: 75%;

      .message-content {
        background: color-mix(in srgb, var(--local-accent) 20%, transparent);
        color: var(--on-primary, var(--foreground));
        backdrop-filter: blur(8px);
        -webkit-backdrop-filter: blur(8px);
        border: 1px solid
          color-mix(in srgb, var(--local-accent) 30%, transparent);
        border-radius: var(--border-radius-xl, 18px);
        border-top-right-radius: var(--border-radius-sm, 4px);
        box-shadow: var(--shadow-sm);
      }
    }
  }

  &.first-in-group {
    margin-top: 16px;
  }

  &.last-in-group {
    margin-bottom: 16px;
  }

  &.message-system {
    justify-content: center;
    max-width: 100%;
    margin: 12px 0;

    .message-content {
      background: transparent;
      border: none;
      box-shadow: none;
      padding: 4px 12px;
      font-size: 0.75rem;
      color: var(--foreground);
      opacity: 0.6;
      font-style: italic;
    }
  }
}

.message-avatar {
  flex-shrink: 0;
  width: 32px;
  height: 32px;
}

.message-bubble {
  flex: 1;
  max-width: 70%;
  display: flex;
  flex-direction: column;
}

.message-content {
  padding: 10px 14px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.message-sender-name {
  font-family: var(--font-heading, inherit);
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--foreground);
  margin-bottom: 2px;
  letter-spacing: 0.01em;
}

.message-text {
  color: var(--foreground);
  line-height: 1.4;
  word-wrap: break-word;
  white-space: pre-wrap;

  .message-sent & {
    color: var(--on-primary, var(--foreground));
  }
}

.message-footer {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 4px;
  margin-top: 4px;
}

.message-timestamp {
  font-family: var(--font-body, inherit);
  font-size: 0.65rem;
  color: var(--foreground);
  opacity: 0.6;

  .message-sent & {
    color: color-mix(in srgb, var(--on-primary, var(--foreground)) 75%, transparent);
  }
}

.message-status {
  display: flex;
  align-items: center;
}

.status-icon {
  width: 16px;
  height: 16px;
  border-radius: 50%;
  border: 2px solid currentColor;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;

  &.sent {
    background: transparent;
    border-color: color-mix(
      in srgb,
      var(--on-primary, var(--foreground)) 60%,
      transparent
    );

    &::after {
      content: '✓';
      font-size: 9px;
      font-weight: bold;
      color: var(--on-primary, var(--foreground));
    }
  }

  &.delivered {
    background: transparent;
    border-color: color-mix(
      in srgb,
      var(--on-primary, var(--foreground)) 80%,
      transparent
    );

    &::after {
      content: '✓✓';
      font-size: 8px;
      font-weight: bold;
      color: var(--on-primary, var(--foreground));
      letter-spacing: -0.5px;
    }
  }

  &.seen {
    background: var(--success);
    border-color: var(--success);

    &::after {
      content: '✓✓';
      font-size: 8px;
      font-weight: bold;
      color: var(--on-primary, var(--foreground));
      letter-spacing: -0.5px;
    }
  }

  &.system {
    display: none;
  }

  &.deleted {
    opacity: 0.5;
  }
}

.edited-label {
  font-size: 0.6rem;
  color: var(--foreground);
  opacity: 0.5;
  font-style: italic;
}

.deleted-text {
  font-style: italic;
  opacity: 0.6;
}

.message-reactions {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-top: 4px;
}

.reaction-badge {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  padding: 2px 6px;
  border: 1px solid var(--local-border-color);
  border-radius: 12px;
  background: var(--surface, var(--background));
  font-size: 0.75rem;
  cursor: pointer;
  transition: all 0.15s ease;

  &:hover {
    background: var(--local-accent-transparent);
  }

  &.active {
    background: var(--local-accent-transparent);
    border-color: var(--local-accent);
  }
}

.add-reaction-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border: 1px solid var(--local-border-color);
  border-radius: 50%;
  background: var(--surface, var(--background));
  font-size: 0.75rem;
  cursor: pointer;
  opacity: 0.6;
  transition: all 0.15s ease;

  &:hover {
    opacity: 1;
    background: var(--local-accent-transparent);
  }
}

.emoji-picker {
  display: flex;
  gap: 4px;
  padding: 8px;
  background: var(--surface, var(--background));
  border: 1px solid var(--local-border-color);
  border-radius: 8px;
  margin-top: 4px;
}

.emoji-btn {
  padding: 4px;
  border: none;
  background: transparent;
  font-size: 1.25rem;
  cursor: pointer;
  border-radius: 4px;
  transition: background 0.15s ease;

  &:hover {
    background: var(--local-accent-transparent);
  }
}

.typing-indicator {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  font-size: 0.8rem;
  color: var(--foreground);
  opacity: 0.7;
}

.typing-dots {
  display: flex;
  gap: 3px;

  span {
    width: 6px;
    height: 6px;
    background: var(--foreground);
    border-radius: 50%;
    animation: typing-bounce 1.4s infinite ease-in-out;

    &:nth-child(1) {
      animation-delay: 0s;
    }

    &:nth-child(2) {
      animation-delay: 0.2s;
    }

    &:nth-child(3) {
      animation-delay: 0.4s;
    }
  }
}

@keyframes typing-bounce {
  0%,
  80%,
  100% {
    transform: scale(0.6);
    opacity: 0.5;
  }
  40% {
    transform: scale(1);
    opacity: 1;
  }
}

.typing-text {
  font-style: italic;
}

